  // Control FSM for aes core.
  //----------------------------------------------------------------
  always @*
    begin : aes_core_ctrl
      init_state       = 1'b0;
      ready_new        = 1'b0;
      ready_we         = 1'b0;
      result_valid_new = 1'b0;
      result_valid_we  = 1'b0;
      aes_core_ctrl_new = CTRL_IDLE;
      aes_core_ctrl_we  = 1'b0;

